contracts/CloneFactory.sol.content:
// SPDX-License-Identifier: Apache-2.0
pragma solidity 0.8.27;

/**
 * @title CloneFactory
 * @notice EIP-1167 minimal proxy deployer using CREATE2
 */
contract CloneFactory {
    // --- Custom Errors ---
    error CloneCreationFailed();

    /**
     * @notice Deploys a minimal proxy (EIP-1167) clone of `target` using CREATE2
     * @param target The implementation contract address
     * @param salt The CREATE2 salt
     * @return result The address of the newly deployed clone
     */
    function createClone(address target, bytes32 salt) internal returns (address payable result) {
        bytes20 targetBytes = bytes20(target);
        // solhint-disable-next-line no-inline-assembly
        assembly {
            let clone := mload(0x40)
            mstore(clone, 0x3d602d80600a3d3981f3363d3d373d3d3d363d73000000000000000000000000)
            mstore(add(clone, 0x14), targetBytes)
            mstore(add(clone, 0x28), 0x5af43d82803e903d91602b57fd5bf30000000000000000000000000000000000)
            result := create2(0, clone, 0x37, salt)
        }
        if (result == address(0)) revert CloneCreationFailed();
    }

    /**
     * @notice Predicts the CREATE2 address of a minimal proxy clone
     * @param target The implementation contract address
     * @param salt The CREATE2 salt
     * @return predicted The predicted address
     */
    function computeCloneAddress(address target, bytes32 salt) internal view returns (address predicted) {
        bytes20 targetBytes = bytes20(target);
        bytes memory bytecode = abi.encodePacked(
            hex"3d602d80600a3d3981f3363d3d373d3d3d363d73",
            targetBytes,
            hex"5af43d82803e903d91602b57fd5bf3"
        );
        bytes32 bytecodeHash = keccak256(bytecode);
        predicted = address(
            uint160(
                uint256(
                    keccak256(
                        abi.encodePacked(bytes1(0xff), address(this), salt, bytecodeHash)
                    )
                )
            )
        );
    }
}

contracts/CvhBatcher.sol.content:
// SPDX-License-Identifier: Apache-2.0
pragma solidity 0.8.27;

import "@openzeppelin/contracts/access/Ownable2Step.sol";
import "./TransferHelper.sol";

/**
 * @title CvhBatcher
 * @notice Batch transfer contract for ETH and ERC20 tokens
 */
contract CvhBatcher is Ownable2Step {
    // --- Custom Errors ---
    error UnequalLengths();
    error EmptyBatch();
    error ExceedsBatchLimit();
    error ZeroAddressRecipient();
    error TransferFailed();
    error InsufficientETH();
    error RefundFailed();
    error RecoverFailed();
    error GasLimitOutOfRange();
    error BatchLimitOutOfRange();

    // --- Events ---
    event BatchTransfer(address indexed sender, address recipient, uint256 value);
    event TransferGasLimitChange(uint256 newGasLimit);
    event BatchTransferLimitChange(uint256 newLimit);

    // --- State ---
    uint256 public transferGasLimit;
    uint256 public batchTransferLimit;

    constructor() Ownable(msg.sender) {
        transferGasLimit = 30000;
        batchTransferLimit = 255;
    }

    /**
     * @notice Batch transfer ETH to multiple recipients
     * @param recipients Array of recipient addresses
     * @param values Array of values to send
     */
    function batchTransfer(
        address[] calldata recipients,
        uint256[] calldata values
    ) external payable onlyOwner {
        if (recipients.length != values.length) revert UnequalLengths();
        if (recipients.length == 0) revert EmptyBatch();
        if (recipients.length > batchTransferLimit) revert ExceedsBatchLimit();

        // Pre-check total required ETH before any transfers
        uint256 totalRequired = 0;
        for (uint256 i = 0; i < recipients.length;) {
            totalRequired += values[i];
            unchecked { ++i; }
        }
        if (totalRequired > msg.value) revert InsufficientETH();

        // Execute transfers
        for (uint256 i = 0; i < recipients.length;) {
            if (recipients[i] == address(0)) revert ZeroAddressRecipient();
            (bool success, ) = recipients[i].call{value: values[i], gas: transferGasLimit}("");
            if (!success) revert TransferFailed();
            emit BatchTransfer(msg.sender, recipients[i], values[i]);
            unchecked { ++i; }
        }

        // Refund excess
        uint256 excess = msg.value - totalRequired;
        if (excess > 0) {
            (bool refundSuccess, ) = msg.sender.call{value: excess}("");
            if (!refundSuccess) revert RefundFailed();
        }
    }

    /**
     * @notice Batch transfer ERC20 tokens to multiple recipients
     * @param tokenAddress The ERC20 token address
     * @param recipients Array of recipient addresses
     * @param values Array of values to send
     */
    function batchTransferToken(
        address tokenAddress,
        address[] calldata recipients,
        uint256[] calldata values
    ) external onlyOwner {
        if (recipients.length != values.length) revert UnequalLengths();
        if (recipients.length == 0) revert EmptyBatch();
        if (recipients.length > batchTransferLimit) revert ExceedsBatchLimit();

        for (uint256 i = 0; i < recipients.length;) {
            if (recipients[i] == address(0)) revert ZeroAddressRecipient();
            TransferHelper.safeTransfer(tokenAddress, recipients[i], values[i]);
            emit BatchTransfer(msg.sender, recipients[i], values[i]);
            unchecked { ++i; }
        }
    }

    /**
     * @notice Set the gas limit for individual transfers
     */
    function setTransferGasLimit(uint256 _transferGasLimit) external onlyOwner {
        if (_transferGasLimit < 2300 || _transferGasLimit > 500000) revert GasLimitOutOfRange();
        transferGasLimit = _transferGasLimit;
        emit TransferGasLimitChange(_transferGasLimit);
    }

    /**
     * @notice Set the maximum batch size
     */
    function setBatchTransferLimit(uint256 _batchTransferLimit) external onlyOwner {
        if (_batchTransferLimit == 0 || _batchTransferLimit > 255) revert BatchLimitOutOfRange();
        batchTransferLimit = _batchTransferLimit;
        emit BatchTransferLimitChange(_batchTransferLimit);
    }

    /**
     * @notice Recover ETH stuck in contract
     * @param to Recipient address
     */
    function recover(address payable to) external onlyOwner {
        uint256 balance = address(this).balance;
        if (balance > 0) {
            (bool success, ) = to.call{value: balance}("");
            if (!success) revert RecoverFailed();
        }
    }
}

contracts/CvhForwarder.sol.content:
// SPDX-License-Identifier: Apache-2.0
pragma solidity 0.8.27;

import "@openzeppelin/contracts/token/ERC721/IERC721.sol";
import "@openzeppelin/contracts/token/ERC721/IERC721Receiver.sol";
import "@openzeppelin/contracts/token/ERC1155/IERC1155.sol";
import "@openzeppelin/contracts/token/ERC1155/IERC1155Receiver.sol";
import "@openzeppelin/contracts/utils/introspection/ERC165.sol";
import "@openzeppelin/contracts/utils/introspection/IERC165.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./interfaces/IERC20.sol";
import "./TransferHelper.sol";

/**
 * @title CvhForwarder
 * @notice Deposit address contract that auto-forwards ETH to the parent wallet
 */
contract CvhForwarder is IERC721Receiver, IERC1155Receiver, ERC165, ReentrancyGuard {
    // --- Custom Errors ---
    error AlreadyInitialized();
    error ZeroParentAddress();
    error ZeroFeeAddress();
    error NotAllowed();
    error NotParent();
    error FlushFailed();
    error CallFailed();
    error TooManyTokens();

    // --- Events ---
    event ForwarderDeposited(address from, uint256 value);
    event AutoFlush721Changed(bool enabled);
    event AutoFlush1155Changed(bool enabled);

    // --- State ---
    bool public initialized;
    address payable public parentAddress;
    address public feeAddress;
    bool public autoFlush721;
    bool public autoFlush1155;

    // --- Constructor (disable init on implementation) ---
    constructor() {
        initialized = true;
    }

    // --- Modifiers ---
    modifier onlyAllowedAddress() {
        if (msg.sender != parentAddress && msg.sender != feeAddress) revert NotAllowed();
        _;
    }

    modifier onlyParent() {
        if (msg.sender != parentAddress) revert NotParent();
        _;
    }

    /**
     * @notice Initialize the forwarder
     * @param _parentAddress The parent wallet address
     * @param _feeAddress The fee address
     * @param _autoFlush721 Whether to auto-forward ERC721 tokens
     * @param _autoFlush1155 Whether to auto-forward ERC1155 tokens
     */
    function init(
        address _parentAddress,
        address _feeAddress,
        bool _autoFlush721,
        bool _autoFlush1155
    ) external {
        if (initialized) revert AlreadyInitialized();
        if (_parentAddress == address(0)) revert ZeroParentAddress();
        if (_feeAddress == address(0)) revert ZeroFeeAddress();

        parentAddress = payable(_parentAddress);
        feeAddress = _feeAddress;
        autoFlush721 = _autoFlush721;
        autoFlush1155 = _autoFlush1155;
        initialized = true;

        // If contract has ETH balance at init, flush immediately
        uint256 balance = address(this).balance;
        if (balance > 0) {
            _flush();
        }
    }

    /**
     * @notice Flush all ETH to parent (restricted to parent/feeAddress)
     */
    function flush() external onlyAllowedAddress nonReentrant {
        _flush();
    }

    function _flush() internal {
        uint256 balance = address(this).balance;
        if (balance > 0) {
            (bool success, ) = parentAddress.call{value: balance}("");
            if (!success) revert FlushFailed();
            emit ForwarderDeposited(address(this), balance);
        }
    }

    /**
     * @notice Flush ERC20 tokens to parent
     * @param tokenContractAddress The ERC20 token address
     */
    function flushTokens(address tokenContractAddress) external onlyAllowedAddress nonReentrant {
        ERC20Interface token = ERC20Interface(tokenContractAddress);
        uint256 balance = token.balanceOf(address(this));
        if (balance > 0) {
            TransferHelper.safeTransfer(tokenContractAddress, parentAddress, balance);
        }
    }

    /**
     * @notice Batch flush multiple ERC20 tokens to parent
     * @param tokenContractAddresses Array of ERC20 token addresses
     */
    function batchFlushERC20Tokens(address[] calldata tokenContractAddresses) external onlyAllowedAddress nonReentrant {
        if (tokenContractAddresses.length > 255) revert TooManyTokens();
        for (uint256 i = 0; i < tokenContractAddresses.length;) {
            ERC20Interface token = ERC20Interface(tokenContractAddresses[i]);
            uint256 balance = token.balanceOf(address(this));
            if (balance > 0) {
                TransferHelper.safeTransfer(tokenContractAddresses[i], parentAddress, balance);
            }
            unchecked { ++i; }
        }
    }

    /**
     * @notice Flush an ERC721 token to parent
     * @param tokenContractAddress The ERC721 token address
     * @param tokenId The token ID
     */
    function flushERC721Token(
        address tokenContractAddress,
        uint256 tokenId
    ) external onlyAllowedAddress {
        IERC721(tokenContractAddress).safeTransferFrom(address(this), parentAddress, tokenId);
    }

    /**
     * @notice Flush ERC1155 tokens to parent
     * @param tokenContractAddress The ERC1155 token address
     * @param tokenId The token ID
     */
    function flushERC1155Tokens(
        address tokenContractAddress,
        uint256 tokenId
    ) external onlyAllowedAddress {
        uint256 balance = IERC1155(tokenContractAddress).balanceOf(address(this), tokenId);
        if (balance > 0) {
            IERC1155(tokenContractAddress).safeTransferFrom(
                address(this),
                parentAddress,
                tokenId,
                balance,
                ""
            );
        }
    }

    /**
     * @notice Set auto-flush for ERC721
     */
    function setAutoFlush721(bool _autoFlush721) external onlyAllowedAddress {
        autoFlush721 = _autoFlush721;
        emit AutoFlush721Changed(_autoFlush721);
    }

    /**
     * @notice Set auto-flush for ERC1155
     */
    function setAutoFlush1155(bool _autoFlush1155) external onlyAllowedAddress {
        autoFlush1155 = _autoFlush1155;
        emit AutoFlush1155Changed(_autoFlush1155);
    }

    /**
     * @notice Execute an arbitrary call from the parent
     * @param target Target address
     * @param value ETH value
     * @param data Call data
     */
    function callFromParent(
        address target,
        uint256 value,
        bytes calldata data
    ) external onlyParent returns (bytes memory) {
        (bool success, bytes memory returnData) = target.call{value: value}(data);
        if (!success) revert CallFailed();
        return returnData;
    }

    // --- NFT auto-forwarding ---

    function onERC721Received(
        address,
        address,
        uint256 tokenId,
        bytes calldata
    ) external override nonReentrant returns (bytes4) {
        if (autoFlush721) {
            // Try to forward to parent. Use try/catch to check if parent supports IERC721Receiver
            try IERC165(parentAddress).supportsInterface(type(IERC721Receiver).interfaceId) returns (bool supported) {
                if (supported) {
                    IERC721(msg.sender).safeTransferFrom(address(this), parentAddress, tokenId);
                } else {
                    IERC721(msg.sender).transferFrom(address(this), parentAddress, tokenId);
                }
            } catch {
                IERC721(msg.sender).transferFrom(address(this), parentAddress, tokenId);
            }
        }
        return IERC721Receiver.onERC721Received.selector;
    }

    function onERC1155Received(
        address,
        address,
        uint256 id,
        uint256 value,
        bytes calldata
    ) external override nonReentrant returns (bytes4) {
        if (autoFlush1155) {
            IERC1155(msg.sender).safeTransferFrom(address(this), parentAddress, id, value, "");
        }
        return IERC1155Receiver.onERC1155Received.selector;
    }

    function onERC1155BatchReceived(
        address,
        address,
        uint256[] calldata ids,
        uint256[] calldata values,
        bytes calldata
    ) external override nonReentrant returns (bytes4) {
        if (autoFlush1155) {
            IERC1155(msg.sender).safeBatchTransferFrom(address(this), parentAddress, ids, values, "");
        }
        return IERC1155Receiver.onERC1155BatchReceived.selector;
    }

    function supportsInterface(bytes4 interfaceId) public view virtual override(ERC165, IERC165) returns (bool) {
        return
            interfaceId == type(IERC721Receiver).interfaceId ||
            interfaceId == type(IERC1155Receiver).interfaceId ||
            super.supportsInterface(interfaceId);
    }

    // --- Receive / Fallback ---

    receive() external payable nonReentrant {
        _flush();
    }

    fallback() external payable nonReentrant {
        _flush();
    }
}

contracts/CvhForwarderFactory.sol.content:
// SPDX-License-Identifier: Apache-2.0
pragma solidity 0.8.27;

import "./CloneFactory.sol";
import "./CvhForwarder.sol";

/**
 * @title CvhForwarderFactory
 * @notice Factory for deploying CvhForwarder clones via CREATE2
 */
contract CvhForwarderFactory is CloneFactory {
    // --- Events ---
    event ForwarderCreated(address forwarderAddress, address parentAddress, address feeAddress);

    // --- State ---
    address public immutable implementationAddress;

    /**
     * @param _implementationAddress The CvhForwarder implementation address
     */
    constructor(address _implementationAddress) {
        implementationAddress = _implementationAddress;
    }

    /**
     * @notice Deploy a new forwarder clone and initialize it
     * @param parent The parent wallet address
     * @param feeAddress The fee address
     * @param salt User-provided salt
     * @param _autoFlush721 Whether to auto-forward ERC721
     * @param _autoFlush1155 Whether to auto-forward ERC1155
     * @return forwarder The address of the new forwarder
     */
    function createForwarder(
        address parent,
        address feeAddress,
        bytes32 salt,
        bool _autoFlush721,
        bool _autoFlush1155
    ) external returns (address payable forwarder) {
        bytes32 finalSalt = keccak256(abi.encode(msg.sender, parent, feeAddress, salt));
        forwarder = createClone(implementationAddress, finalSalt);
        CvhForwarder(payable(forwarder)).init(parent, feeAddress, _autoFlush721, _autoFlush1155);
        emit ForwarderCreated(forwarder, parent, feeAddress);
    }

    /**
     * @notice Predict the address of a forwarder clone
     * @param deployer The address that will call createForwarder
     * @param parent The parent wallet address
     * @param feeAddress The fee address
     * @param salt User-provided salt
     * @return The predicted address
     */
    function computeForwarderAddress(
        address deployer,
        address parent,
        address feeAddress,
        bytes32 salt
    ) external view returns (address) {
        bytes32 finalSalt = keccak256(abi.encode(deployer, parent, feeAddress, salt));
        return computeCloneAddress(implementationAddress, finalSalt);
    }
}

